SELECT g.gb_dg_goods_name, g.gb_dg_goods_standardname, g.gb_dg_nx_father_img, t.goods_id AS gb_distributer_goods_id, t.max_price AS gbDgGoodsHighestPrice, t.min_price AS gbDgGoodsLowestPrice, t.price_diff AS goodsPriceDiff, -- 价格差额（元） t.price_fluctuation AS goodsPriceFluctuation -- 价格波动率（百分比，保留1位小数） FROM ( SELECT gb_DPG_dis_goods_id AS goods_id, MAX(CAST(gb_DPG_buy_price AS DECIMAL(10, 1))) AS max_price, MIN(CAST(gb_DPG_buy_price AS DECIMAL(10, 1))) AS min_price, ROUND((MAX(CAST(gb_DPG_buy_price AS DECIMAL(10, 1))) - MIN(CAST(gb_DPG_buy_price AS DECIMAL(10, 1)))), 1) AS price_diff, ROUND(((MAX(CAST(gb_DPG_buy_price AS DECIMAL(10, 1))) - MIN(CAST(gb_DPG_buy_price AS DECIMAL(10, 1)))) / MIN(CAST(gb_DPG_buy_price AS DECIMAL(10, 1)))) * 100, 1) AS price_fluctuation FROM gb_distributer_purchase_goods WHERE gb_DPG_stock_finish_date BETWEEN #{startDate} AND #{stopDate} AND gb_DPG_distributer_id = #{disId} AND gb_DPG_buy_price IS NOT NULL AND gb_DPG_status > 2
AND gb_DPG_purchase_type != #{typeNotEqual}
GROUP BY gb_DPG_dis_goods_id ) t JOIN gb_distributer_goods g ON g.gb_distributer_goods_id = t.goods_id ORDER BY t.price_fluctuation DESC LIMIT 10;

SELECT
dg.gb_distributer_goods_id,
dg.gb_dg_goods_name,
dg.gb_dg_nx_father_img,
dg.gb_dg_goods_standardname,
dg.gb_dg_goods_standard_weight,
dg.gb_dg_gb_supplier_id,
-- 原始字段（存表里的最低价、最高价）
dg.gb_dg_goods_lowest_price AS origin_lowest_price,
dg.gb_dg_goods_highest_price AS origin_highest_price,

-- 汇总字段（基于过滤条件计算）
ROUND(SUM(gdpg.gb_DPG_buy_subtotal), 1) AS gb_dg_selling_price,
ROUND(SUM(gdpg.gb_DPG_buy_quantity), 1) AS gb_dg_self_price,

CASE
WHEN dg.gb_dg_goods_lowest_price IS NULL OR dg.gb_dg_goods_lowest_price = ''
THEN MIN(CAST(gdpg.gb_DPG_buy_price AS DECIMAL(10,1)))
ELSE CAST(dg.gb_dg_goods_lowest_price AS DECIMAL(10,1))
END AS lowest_price,
CASE
WHEN dg.gb_dg_goods_highest_price IS NULL OR dg.gb_dg_goods_highest_price = ''
THEN MAX(CAST(gdpg.gb_DPG_buy_price AS DECIMAL(10,1)))
ELSE CAST(dg.gb_dg_goods_highest_price AS DECIMAL(10,1))
END AS highest_price,
ROUND(AVG(CAST(gdpg.gb_DPG_buy_price AS DECIMAL(10,1))), 1) AS average_price,

COUNT(*) AS buy_count,
